import React, { useCallback, useMemo, useState } from 'react';
import { FiUsers } from 'react-icons/fi';
import { useOutletContext } from 'react-router-dom';
import DataTable from '../components/DataTable';
import UserForm from '../components/UserForm';
import { users as initialUsers } from '../utils/sampleData';

const Users = () => {
  const [data, setData] = useState(initialUsers);
  const [message, setMessage] = useState('');
  const { searchTerm } = useOutletContext();

  const deleteUser = useCallback((id) => {
    const confirmed = window.confirm('Delete this user?');
    if (confirmed) {
      setData((prev) => prev.filter((user) => user.id !== id));
      setMessage('User deleted successfully.');
    }
  }, []);

  const editUser = useCallback((user) => {
    setMessage(`Editing ${user.name}`);
  }, []);

  const activeCount = useMemo(() => data.filter((user) => user.status === 'Active').length, [data]);
  const filteredUsers = useMemo(() => {
    const query = searchTerm.trim().toLowerCase();
    if (!query) return data;
    return data.filter((user) => user.name.toLowerCase().includes(query) || user.email.toLowerCase().includes(query));
  }, [data, searchTerm]);

  return (
    <div className="space-y-6">
      <div className="rounded-2xl border border-slate-200 bg-white p-6 shadow-sm">
        <div className="flex flex-wrap items-center justify-between gap-3">
          <div className="flex items-center gap-3">
            <div className="rounded-xl bg-blue-600 p-3 text-white">
              <FiUsers className="h-5 w-5" />
            </div>
            <div>
              <h3 className="text-lg font-semibold text-slate-900">User Management</h3>
              <p className="text-sm text-slate-500">Manage active users and roles</p>
            </div>
          </div>
          <div className="rounded-full bg-emerald-100 px-3 py-1 text-sm font-semibold text-emerald-700">{activeCount} Active</div>
        </div>
      </div>

      {message && <div className="rounded-xl border border-emerald-200 bg-emerald-50 px-4 py-3 text-sm text-emerald-800">{message}</div>}

      <UserForm onSubmitSuccess={() => setMessage('User created successfully.')} />

      {filteredUsers.length > 0 ? (
        <DataTable data={filteredUsers} onEdit={editUser} onDelete={deleteUser} />
      ) : (
        <div className="rounded-2xl border border-dashed border-slate-300 bg-white p-10 text-center text-slate-500">No users match your search.</div>
      )}
    </div>
  );
};

export default Users;
